// ============================================================
// ボタン1個分のHTMLを生成するヘルパー
// ============================================================

function torehaji_render_aff_button(array $link, string $css_class, string $label): string
{

  // href が空 = 未設定 → 出力しない
  if (empty($link['href'])) {
    return '';
  }

  $href       = esc_url($link['href']);
  $impression = ! empty($link['impression']) ? esc_url($link['impression']) : '';

  $html  = '<li class="' . esc_attr($css_class) . '">';
  $html .= '<a href="' . $href . '" rel="nofollow" referrerpolicy="no-referrer-when-downgrade" target="_blank">';
  $html .= esc_html($label);
  $html .= '</a>';

  // インプレッションピクセルがある場合のみ出力
  if ($impression) {
    $html .= '<img src="' . $impression . '" alt="" loading="lazy" width="1" height="1" style="border:none;" />';
  }

  $html .= '</li>';

  return $html;
}


// ============================================================
// 購入ボタン ショートコード本体
// 使い方: [protein_buy_buttons id="be-legend"]
// ============================================================

function torehaji_protein_buy_buttons(array $atts): string
{

  $atts = shortcode_atts(
    ['id' => ''],
    $atts,
    'protein_buy_buttons'
  );

  $id       = sanitize_key($atts['id']);
  $products = torehaji_get_protein_products();

  if (empty($id) || ! isset($products[$id])) {
    return '';
  }

  $p = $products[$id];

  $buttons  = torehaji_render_aff_button($p['official'] ?? [], 'item_official', '公式サイトで購入する');
  $buttons .= torehaji_render_aff_button($p['amazon']   ?? [], 'item_amazon',   'Amazonで購入する');
  $buttons .= torehaji_render_aff_button($p['rakuten']  ?? [], 'item_rakuten',  '楽天市場で購入する');
  $buttons .= torehaji_render_aff_button($p['yahoo']    ?? [], 'item_yahoo',    'Yahoo!ショッピングで購入する');

  // ボタンが1つも出力されなければ何も返さない
  if (empty(trim($buttons))) {
    return '';
  }

  return '<div class="protein-rank-card__asp-area"><ul class="item_btn">' . $buttons . '</ul></div>';
}

add_shortcode('protein_buy_buttons', 'torehaji_protein_buy_buttons');


